{
  "claims": [
    {
      "claim_text": "California has provided a meager $200 to individuals upon their release from the California Department of Corrections and Rehabilitation (CDCR) for post-release expenses related to transportation, clothing, and other essential expenses since 1973."
    },
    {
      "claim_text": "CDCR can deduct money from the release allowance to cover the costs of transportation and clothing."
    },
    {
      "claim_text": "Many individuals receive less than $120 to meet their basic needs in the critical first days after their release due to these deductions."
    },
    {
      "claim_text": "Senator Becker secured a $1.8 million investment to ensure that the full release allowance is given to individuals without any deductions."
    },
    {
      "claim_text": "This investment is expected to benefit approximately 10,000 individuals each year affected by these deductions."
    },
    {
      "claim_text": "Providing the full release allowance is vital for successful reentry and the overall well-being of communities."
    }
  ]
}
